"""
mkt-original layer — Philippians chapters 1–3 (full coverage)
Output: data/commentary/mkt-original/philippians.json
Run: python3 scripts/zc-original-philippians-1-3-full.py

Covers all missing verses; merge_comm skips already-present keys.
Key decisions: koinōnia = participation/partnership (not just 'fellowship');
politeuesthe = 'live as citizens'; morphē theou = mode of divine existence
(not mere appearance); skybala = dung/rubbish (full force preserved).
"""
import json, pathlib

ROOT = pathlib.Path(__file__).parent.parent

def load_comm(source, book):
    p = ROOT / 'data' / 'commentary' / source / f'{book}.json'
    if p.exists():
        return json.loads(p.read_text())
    return {}

def save_comm(source, book, data):
    p = ROOT / 'data' / 'commentary' / source / f'{book}.json'
    p.parent.mkdir(parents=True, exist_ok=True)
    p.write_text(json.dumps(data, ensure_ascii=False, indent=None))
    print(f'  wrote {p.relative_to(ROOT)}')

def merge_comm(existing, new_data):
    # INTENT: Merge new verse entries without overwriting already-present keys — safe to re-run.
    # CHANGE? If commentary JSON structure changes from {ch:{v:html}}, update this traversal.
    # VERIFY: Re-running the script should produce identical output.
    for ch, verses in new_data.items():
        if ch not in existing:
            existing[ch] = {}
        for v, html in verses.items():
            if v not in existing[ch]:
                existing[ch][v] = html

NEW = {
  "1": {
    "1": "<p><strong>Paulos kai Timotheos douloi Christou Iesou pasin tois hagiois en Christo Iesou tois ousin en Philippois syn episkopois kai diakonois</strong>: Paul and Timothy, <em>douloi Christou Iesou</em> (slaves of Christ Jesus). The self-designation <em>doulos</em> (slave) is Paul's strongest claim of belonging and subordination — the slave has no autonomous will. <em>Episkopois kai diakonois</em> (overseers and deacons) — this is the earliest datable use of these two terms together as distinct offices. <em>Episkopos</em> (overseer) denotes supervisory leadership; <em>diakonos</em> (servant/minister/deacon) denotes functional service. Philippians is uniquely addressed to the leaders alongside the whole congregation.</p>",
    "2": "<p><strong>charis hymin kai eirene apo theou patros hemon kai kyriou Iesou Christou</strong>: Grace (<em>charis</em>) and peace (<em>eirēnē</em>) — the Pauline greeting fusing Greek (<em>chairein</em>) and Hebrew (<em>shalom</em>) in a theologically loaded form. The dual source (God the Father and Lord Jesus Christ) is Paul's standard binitarian greeting-formula, asserting that the grace and peace flow from both Father and Son as a unified divine source.</p>",
    "3": "<p><strong>eucharisto to theo mou epi pase te mneia hymon</strong>: 'I thank my God in all my remembrance of you' — the thanksgiving period (1:3-11) is one of Paul's warmest. <em>Eucharistō</em> (I give thanks) is the Greek verb from which <em>eucharist</em> derives. The possessive <em>to theo mou</em> (my God) reflects the personal relationship language of the Psalms.</p>",
    "4": "<p><strong>pantote en pase deēsei mou hyper pantōn hymōn meta charas tēn deesin poioumenos</strong>: 'always in every prayer of mine for you all, making my prayer with joy' — <em>deēsis</em> (petition, prayer-request) and <em>chara</em> (joy) are the twin notes of the letter's opening. Joy (<em>chara</em>/<em>chairō</em>) appears 16 times in Philippians — the most joy-saturated letter in the Pauline corpus, written from prison.</p>",
    "5": "<p><strong>epi tē koinōnia hymōn eis to euangelion apo tēs prōtēs hēmeras achri tou nyn</strong>: 'because of your <em>koinōnia</em> in the gospel from the first day until now.' <em>Koinōnia</em> (partnership, participation, fellowship) is the letter's key relational term. It denotes not merely emotional fellowship but active sharing — the Philippians' financial partnership in Paul's missionary work (4:15-17: no church shared with me in giving and receiving except you) and their participation in the gospel project itself. <em>Euangelion</em> (gospel, good news) is the content of the partnership.</p>",
    "6": "<p><strong>pepoithōs auto touto hoti ho enarcxamenos en hymin ergon agathon epitelesei achri hēmeras Christou Iesou</strong>: 'being confident of this very thing, that he who began a good work in you will bring it to completion at the day of Christ Jesus.' The eschatological confidence is grounded in divine faithfulness: God who initiated (<em>ho enarcxamenos</em>) will also complete (<em>epitelesei</em>). The <em>hēmera Christou Iesou</em> (day of Christ Jesus) — the parousia as the telos of the divine work — appears 3 times in vv.6-11.</p>",
    "7": "<p><strong>kathōs estin dikaion emoi touto phronein hyper pantōn hymōn dia to echein me en tē kardia hymas</strong>: 'It is right for me to feel this way about you all, because I hold you in my heart.' <em>Phronein</em> (to think, feel, have this mindset) — the key verb of Philippians, appearing 10 times. <em>Kardia</em> (heart) as the seat of commitment and will. Both in my imprisonment and in the defense (<em>apologia</em>) and confirmation (<em>bebaiōsis</em>) of the gospel, you are all partakers (<em>synkoinōnous</em>) with me of grace.</p>",
    "8": "<p><strong>martys gar mou ho theos hōs epipothō pantas hymas en splanchnois Christou Iesou</strong>: 'For God is my witness, how I yearn for you all with the affection (<em>splanchnois</em>) of Christ Jesus.' <em>Splanchnon</em> (bowels, gut, deep affection) was the ancient term for the seat of compassion — the visceral center of feeling. The genitive <em>Christou Iesou</em> is significant: Paul's yearning is the yearning of Christ himself, not merely Paul's own affection. The apostle has become so identified with Christ that Christ's own compassion flows through him.</p>",
    "9": "<p><strong>kai touto proseuchomai hina hē agapē hymōn eti mallon kai mallon perisseuē en epignōsei kai pasē aisthēsei</strong>: 'And it is my prayer that your love may abound more and more, with <em>epignōsis</em> (full/genuine knowledge) and all discernment (<em>aisthēsis</em>).' <em>Epignōsis</em> (epi + gnōsis) is the intensified knowledge — thorough, personal, relational knowing rather than mere intellectual acquaintance. <em>Aisthēsis</em> (moral perception, discernment) — the trained capacity to recognize what is genuinely good (v.10: dokimazein ta diapheronta — to approve what is excellent).</p>",
    "10": "<p><strong>eis to dokimazein hymas ta diapheronta hina ēte eilikrineis kai aproskopoi eis hēmeral Christou</strong>: 'so that you may approve what is excellent (<em>ta diapheronta</em>), and so be pure and blameless for the day of Christ.' <em>Dokimazein</em> (to test, approve through testing) — the word for assaying metal. <em>Ta diapheronta</em> (the things that differ, the excellent things) — Paul prays for the Philippians' moral discernment to identify what genuinely matters among competing goods. <em>Eilikrineis</em> (pure, sincere — possibly from <em>eilē</em> + <em>krinō</em>, judged in sunlight): transparent under examination.</p>",
    "11": "<p><strong>peplērōmenoi karpon dikaiosynēs ton dia Iesou Christou eis doxan kai epainon theou</strong>: 'filled with the fruit of righteousness that comes through Jesus Christ, to the glory and praise of God.' <em>Karpos dikaiosynēs</em> (fruit of righteousness) echoes the prophetic tradition (Amos 6:12 LXX; Prov 11:30; Isa 32:17: the fruit of righteousness will be peace). The righteousness is not earned by the Philippians but comes <em>through Jesus Christ</em> — its source and channel is christological. Its goal: God's glory and praise.</p>",
    "12": "<p><strong>ginōskein de hymas boulomai adelphoi hoti ta kat' eme mallon eis prokopēn tou euangeliou elēlythen</strong>: 'I want you to know, brothers, that what has happened to me has really served to advance (<em>prokopēn</em>) the gospel.' <em>Prokopē</em> (progress, advance) was a Stoic philosophical term for moral progress toward the ideal sage. Paul uses it for the gospel's advance — the unexpected instrument being his imprisonment. The paradox: chains became a pulpit.</p>",
    "13": "<p><strong>hōste tous desmous mou phaneroys en Christō genesthai en holō tō praitōriō kai tois loipois pasin</strong>: 'so that it has become known throughout the whole praetorian guard and to all the rest that my imprisonment is for Christ.' <em>Praitorion</em> (Praetorium) — most naturally the Praetorian Guard headquarters in Rome. <em>En Christō</em> (in/for Christ) — the chains are christologically defined: not punishment but martyrdom. The Praetorian soldiers knew why Paul was imprisoned; the gospel explanation defined the captivity.</p>",
    "14": "<p><strong>kai tous pleionas tōn adelphōn en kyriō pepoithotas tois desmois mou perissoteros tolman adeoōs ton logon lalein</strong>: 'and most of the brothers, having become confident in the Lord by my imprisonment, are much more bold to speak the word without fear.' The apostle's imprisonment emboldened rather than silenced the broader community. The gospel's advance came through Paul's chains AND through those his chains inspired. <em>Adeoōs</em> (fearlessly, without hesitation) — the courage directly proportional to the apostle's willingness to suffer.</p>",
    "15": "<p><strong>tines men kai dia phthonon kai erin, tines de kai di' eudokian ton Christon kēryssousin</strong>: 'Some indeed preach Christ from envy and rivalry, but others from good will.' The remarkable acknowledgment: Christ is preached with mixed motives — envy, rivalry, faction. <em>Phthonos</em> (envy) and <em>eris</em> (strife) were standard vices in Greco-Roman catalogues. Paul does not identify these preachers (rival Paulinists? Jewish-Christian missionaries?); the point is their motivation, not their theology.</p>",
    "16": "<p><strong>hoi men ex agapēs eidotes hoti eis apologian tou euangeliou keimai</strong>: 'the latter do it out of love, knowing that I am put here for the defense of the gospel.' <em>Apologia</em> (defense, legal defense) — the term for a formal judicial defense speech. Paul frames his imprisonment as an ongoing legal defense of the gospel before Roman authorities. Those who preach from love understand this; those who preach from rivalry are, by contrast, presenting Paul's imprisonment as his failure.</p>",
    "17": "<p><strong>hoi de ex eritheias ton Christon katangellousin ouch hagnōs, oiomenoi thlipsin egeirein tois desmois mou</strong>: 'the former proclaim Christ out of selfish ambition (<em>eritheias</em>), not sincerely, thinking to afflict me in my imprisonment.' <em>Eritheia</em> (selfish ambition, factional self-seeking) — originally the term for day-labor for hire, suggesting mercenary motivation. These preachers apparently believe their success embarrasses the imprisoned Paul or proves his methods deficient.</p>",
    "18": "<p><strong>ti gar; plēn hoti panti tropō, eite prophasei eite alētheia, Christos katangelletai, kai en toutō chairō</strong>: 'What then? Only that in every way, whether in pretense or in truth, Christ is proclaimed, and in that I rejoice.' The striking pastoral magnanimity: Paul rejoices that Christ is preached even by those whose motives he questions. The object of proclamation — Christ — is what matters, not the purity of the proclaimer's motives. Yes, and I will rejoice — <em>chairō</em> shifts to the future: the joy is not circumstance-dependent.</p>",
    "19": "<p><strong>oida gar hoti touto moi apobēsetai eis sōtērian dia tēs hymōn deēseōs kai epichorēgias tou pneumatos Iēsou Christou</strong>: 'for I know that through your prayers and the help (<em>epichorēgia</em>) of the Spirit of Jesus Christ this will turn out for my deliverance (<em>sōtērian</em>).' <em>Epichorēgia</em> (supply, provision, full equipping) — originally the wealthy citizen's sponsorship of a chorus. The Spirit's provision is bountiful supply. <em>Sōtēria</em> here likely means both immediate rescue and eschatological salvation — Paul is content with either outcome (vv.20-26).</p>",
    "20": "<p><strong>kata tēn apokaradokian kai elpida mou hoti en oudeni aiscynthēsomai alla en pasē parrēsia hōs pantote kai nyn megalynthēsetai Christos en tō sōmati mou</strong>: 'as it is my eager expectation (<em>apokaradokia</em>) and hope that I will not be at all ashamed, but that with full courage (<em>parrēsia</em>) now as always Christ will be honored (<em>megalynthēsetai</em>) in my body.' <em>Apokaradokia</em> (eager expectation, neck-craning anticipation) — a Pauline compound (Rom 8:19 also) conveying intense forward-straining. Christ honored/magnified in Paul's body — whether through life or death (v.20b); the body is the apostolic field of Christological display.</p>",
    "21": "<p><strong>emoi gar to zēn Christos kai to apothanein kerdos</strong>: 'For to me to live is Christ and to die is gain.' The most compressed summary of Paul's existential situation. <em>To zēn Christos</em>: life = Christ, not a christological supplement to normal life but its complete content. <em>To apothanein kerdos</em>: death = gain — not because life is bad but because death means fuller presence with Christ (v.23). The equation is not escapist but participatory: life fully in Christ, death more fully in Christ.</p>",
    "22": "<p><strong>ei de to zēn en sarki, touto moi karpos ergou</strong>: 'If I am to live in the flesh, that means fruitful labor for me.' The tension between the two goods: continued life produces fruit (<em>karpos ergou</em>) for the congregation; death produces gain for Paul. The apostolic vocation suspends personal preference: the congregation's need takes priority over personal desire (v.24: to remain in the flesh is more necessary for your sake).</p>",
    "23": "<p><strong>synechomai de ek tōn dyo, tēn epithymian echōn eis to analyein kai syn Christō einai, pollō [gar] mallon kreisson</strong>: 'I am hard pressed between the two. My desire is to depart (<em>analyein</em>) and be with Christ, for that is far better.' <em>Synechomai</em> (to be pressed, held in by, constrained) — Paul is caught between two goods. <em>Analyein</em> (to break camp, weigh anchor, depart) — the departure image evokes a ship leaving harbor. <em>Syn Christō einai</em> (to be with Christ) — the goal of death for believers: personal presence with Christ, not mere dissolution.</p>",
    "24": "<p><strong>to de epimenein [en] tē sarki anagkaioteron di' hymas</strong>: 'But to remain in the flesh is more necessary on your account.' The apostle's survival calculus is entirely other-directed: not self-preservation or self-interest but the congregation's need. The pastoral logic of cruciform love: the apostle's continued life is a gift given to the congregation, not a personal preference indulged.</p>",
    "25": "<p><strong>kai touto pepoithōs oida hoti menō kai paramenō pasin hymin eis tēn hymōn prokopēn kai charan tēs pisteōs</strong>: 'Convinced of this, I know that I will remain and continue with you all, for your progress (<em>prokopēn</em>) and joy in the faith.' <em>Prokopē</em> again — the Philippians' advance in faith and joy is the purpose of Paul's continued ministry. The joy (<em>chara tēs pisteōs</em> — joy of faith) encompasses both the apostle's joy and the congregation's joy in the faith they share.</p>",
    "26": "<p><strong>hina to kauchēma hymōn perisseuē en Christō Iēsou en emoi dia tēs emēs parousias palin pros hymas</strong>: 'so that in me you may have ample cause to glory in Christ Jesus, because of my coming (<em>parousias</em>) to you again.' <em>Kauchēma</em> (boast, ground of boasting) — in Christ Jesus: the boasting is not in Paul himself but in Christ through Paul. <em>Parousia</em> (presence, coming) — the same word used for Christ's eschatological coming; Paul's anticipated visit is a mini-parousia of the apostle to his congregation.</p>",
    "27": "<p><strong>monon axiōs tou euangeliou tou Christou politeuesthe</strong>: 'Only let your manner of life (<em>politeuesthe</em>) be worthy of the gospel of Christ.' <em>Politeuesthai</em> (to live as a citizen, to conduct oneself as a member of a polity) — the civic-political verb from <em>polis</em> (city). The Philippians as Roman colonists understood citizenship obligations; Paul redirects their civic identity: the gospel defines the polity in which they live. This verse is the hinge from personal matters (vv.12-26) to community exhortation (1:27-4:9).</p>",
    "28": "<p><strong>kai mē ptyromenoi en mēdeni hypo tōn antikeimenōn</strong>: 'and not frightened in anything by your opponents.' <em>Ptyromenoi</em> (frightened, startled — used of horses shying) — the congregation's steadfastness is itself a sign (<em>endeixis</em>): to the opponents it signals destruction; to the Philippians it signals their salvation, and this from God. The courage of the congregation in the face of opposition is itself apologetic witness.</p>",
    "29": "<p><strong>hoti hymin echaristhē to hyper Christou, ou monon to eis auton pisteuein alla kai to hyper autou paschein</strong>: 'For it has been granted (<em>echaristhē</em> — a grace-gift) to you that for the sake of Christ you should not only believe in him but also suffer for his sake.' The remarkable claim: suffering for Christ is a <em>charisma</em> (grace-gift), not a punishment or failure. The suffering and the faith are equally granted by divine grace — both are God's gifts to the congregation.</p>",
    "30": "<p><strong>ton auton agōna echontes hoion eidete en emoi kai nyn akouete en emoi</strong>: 'engaged in the same conflict (<em>agōna</em>) that you saw I had and now hear that I still have.' <em>Agōn</em> (contest, struggle — from the athletic and gladiatorial arena) — the shared struggle of apostle and congregation. The Philippians saw Paul's first conflict when he was imprisoned in Philippi (Acts 16:19-24); now they hear of his Roman imprisonment. The apostolic pattern of suffering is the congregation's own pattern.</p>",
  },
  "2": {
    "1": "<p><strong>Ei tis oun paraklēsis en Christō, ei ti paramythion agapēs, ei tis koinōnia pneumatos, ei tis splagchna kai oiktirmoi</strong>: 'If there is any encouragement (<em>paraklēsis</em>) in Christ, any comfort (<em>paramythion</em>) from love, any participation (<em>koinōnia</em>) in the Spirit, any affection and sympathy (<em>splagchna kai oiktirmoi</em>).' The fourfold conditional assumes all four conditions are real — the Greek idiom treats them as certainly true. <em>Paraklēsis</em> (encouragement, consolation) shares its root with the Paraclete; <em>paramythion</em> (comfort, consolation through words); <em>koinōnia pneumatos</em> (fellowship/sharing of the Spirit). The appeal is to their shared experience of Christ.</p>",
    "2": "<p><strong>plērōsate mou tēn charan hina to auto phronēte tēn autēn agapēn echontes sympsychoi to hen phronountes</strong>: 'complete my joy by being of the same mind (<em>to auto phronēte</em>), having the same love, being in full accord (<em>sympsychoi</em> — one-souled) and of one mind (<em>to hen phronountes</em>).' The double use of <em>phronein</em> (to have the same mindset) frames the unity appeal. <em>Sympsychoi</em> (knit together in soul) — a Pauline hapax. The unity Paul seeks is not merely behavioral conformity but deep shared orientation and affection.</p>",
    "3": "<p><strong>mēden kat' eritheian mēde kata kenodoxian alla tē tapeinophrosynē allēlous hēgoumenoi hyperechontas heautōn</strong>: 'Do nothing from selfish ambition (<em>eritheian</em>) or conceit (<em>kenodoxian</em>, empty glory/vainglory), but in humility (<em>tapeinophrosynē</em>) count others more significant than yourselves.' <em>Tapeinophrosynē</em> (humility, lowliness of mind) was not a virtue in Greco-Roman culture — it was associated with the servile, the defeated, the socially inferior. Paul installs it as the Christian alternative to Roman honor-competition. <em>Hēgoumenoi hyperechontas heautōn</em>: reckoning others as surpassing oneself — a radical counter-cultural posture.</p>",
    "4": "<p><strong>mē ta heautōn hekastos skopeite alla [kai] ta heterōn hekastos</strong>: 'Let each of you look not only to his own interests, but also to the interests of others.' <em>Skopeite</em> (observe, look to, attend to) — the active consideration of others' concerns alongside one's own. This verse provides the ethical frame that the Christ-hymn (vv.6-11) then grounds christologically: the pattern of not-grasping-for-oneself is the Christ-pattern.</p>",
    "5": "<p><strong>touto phroneite en hymin ho kai en Christō Iēsou</strong>: 'Have this mind (<em>touto phroneite</em>) among yourselves, which is yours in Christ Jesus.' The transition to the Christ-hymn: the mindset Paul calls for is already present in the community through Christ. <em>Phronein</em> here introduces the Christological basis for the ethical appeal. The 'mind of Christ' is not an abstract ideal but the attitude concretely embodied in the narrative of vv.6-11.</p>",
    "7": "<p><strong>alla heauton ekenōsen morphēn doulou labōn en homoiōmati anthrōpōn genomenos</strong>: 'but emptied himself (<em>ekenōsen</em>), by taking the form of a servant (<em>morphēn doulou labōn</em>), being born in the likeness (<em>homoiōmati</em>) of men.' <em>Ekenōsen</em> (from <em>kenoō</em>) — to empty, make void. The Kenotic Christology centers on this verb: the divine Son voluntarily relinquished (not his divine nature but) the independent exercise of divine prerogatives, taking instead the form of a slave. <em>Morphēn doulou</em>: the form of a doulos (slave/servant) is the direct antithesis of <em>morphē theou</em>. The Son of God took the social position of the lowest: the slave who has no rights, whose entire existence is defined by another's will.</p>",
    "8": "<p><strong>kai schēmati heuretheis hōs anthrōpos etapeinōsen heauton genomenos hypēkoos mechri thanatou, thanatou de staurou</strong>: 'And being found in human form (<em>schēmati</em>), he humbled himself by becoming obedient to the point of death, even death on a cross.' <em>Schēma</em> (form, appearance, external configuration — as in the schematic of a plan): Christ was found in the outward configuration of a human being. <em>Etapeinōsen heauton</em> (he humbled himself) — active self-humiliation. <em>Mechri thanatou, thanatou de staurou</em>: 'even to death — death on a cross.' The shocking climax: the cross was Rome's most shameful execution, reserved for the lowest criminals and slaves. The Son of God died a slave's death.</p>",
    "10": "<p><strong>hina en tō onomati Iēsou pan gony kampsē epouraniōn kai epigeiōn kai katachthoniōn</strong>: 'so that at the name of Jesus every knee should bow, in heaven and on earth and under the earth.' The three-level cosmos (heavenly/earthly/subterranean — the classic ancient cosmological division: gods/humans/the dead) bows before the name of Jesus. <em>Kampsē</em> (bend, bow down) — the physical act of submission. The citation of Isa 45:23 applies the absolute claim of YHWH's universal sovereignty to the exalted Jesus.</p>",
    "12": "<p><strong>hōste agapētoi mou kathōs pantote hypēkousate mē hōs en tē parousia mou monon alla nyn pollō mallon en tē apousia mou, meta phobou kai tromou tēn heautōn sōtērian katergazesthe</strong>: 'Therefore, my beloved, as you have always obeyed, so now, not only as in my presence (<em>parousia</em>) but much more in my absence (<em>apousia</em>), work out your own salvation (<em>sōtērian katergazesthe</em>) with fear and trembling (<em>phobou kai tromou</em>).' <em>Katergazesthe</em> (work out, accomplish, bring to completion) — not earn but work out the implications of received salvation. <em>Phobos kai tromos</em>: OT language for the awe of divine encounter (Exod 15:16; Ps 2:11). The fear is reverence before the God who is at work (v.13), not fear of loss of salvation.</p>",
    "13": "<p><strong>ho theos gar estin ho energōn en hymin kai to thelein kai to energein hyper tēs eudokias</strong>: 'for it is God who works (<em>ho energōn</em>) in you, both to will (<em>to thelein</em>) and to work (<em>to energein</em>) for his good pleasure (<em>eudokias</em>).' The divine-human cooperation: God works in them (the indicative ground) so they work out their salvation (the imperative response). Even the will to obey is God's gift. <em>Eudokia</em> (good pleasure, benevolent purpose) — God's working has its source in his own gracious purpose, not in the congregation's merit.</p>",
    "14": "<p><strong>panta poieite chōris gongysmōn kai dialogismōn</strong>: 'Do all things without grumbling (<em>gongysmōn</em>) or disputing (<em>dialogismōn</em>).' <em>Gongysmoi</em> (murmurings, grumblings) — the LXX word for Israel's wilderness complaints against Moses and God (Exod 16:7-12; Num 11:1; 14:27). The echo is deliberate: the Philippians are to do the opposite of Israel in the wilderness. <em>Dialogismoi</em> (disputes, questionings, debates) — internal community conflict that undermines the unified mission.</p>",
    "15": "<p><strong>hina genēsthe amemptoi kai akeraioi tekna theou amōma mesē geneas skolias kai diestrammenēs en hois phainesthē hōs phōstēres en kosmō</strong>: 'that you may be blameless (<em>amemptoi</em>) and innocent (<em>akeraioi</em>), children of God without blemish (<em>amōma</em>) in the midst of a crooked and twisted generation, among whom you shine as lights (<em>phōstēres</em>) in the world.' <em>Amōmos</em> (without blemish — the sacrificial standard) combined with <em>phōstēres</em> (lights, luminaries — the stars of Dan 12:3: those who are wise shall shine like the brightness of the sky). The congregation is Israel-in-the-wilderness reconstituted as the light-bearing community in the crooked generation.</p>",
    "16": "<p><strong>logon zōēs epechontes eis kauchēma emoi eis hēmeran Christou, hoti ouk eis kenon edramon oude eis kenon ekopiasa</strong>: 'holding fast (<em>epechontes</em>) to the word of life, so that in the day of Christ I may be proud that I did not run in vain (<em>eis kenon edramon</em>) or labor in vain.' The athletic metaphor: <em>edramon</em> (I ran) — Paul's apostolic work as a race (1 Cor 9:24-26; Gal 2:2). The fear is <em>kenon</em> (empty, vain) — that the Philippians' failure would nullify the apostolic effort at the day of Christ.</p>",
    "17": "<p><strong>alla ei kai spendomai epi tē thysia kai leitourgia tēs pisteōs hymōn chariō kai synchairō pasin hymin</strong>: 'Even if I am to be poured out as a drink offering (<em>spendomai</em>) upon the sacrificial offering and service (<em>leitourgia</em>) of your faith, I am glad and rejoice with you all.' <em>Spendomai</em> (I am poured out as a libation) — the Roman and Jewish sacrificial practice of pouring wine on the altar as a drink offering. Paul's potential martyrdom is reframed as a libation poured over the Philippians' faith as the primary sacrifice. The apostle's death would be an additional offering over their living faith-offering.</p>",
    "18": "<p><strong>to de auto kai hymeis chairete kai synchairete moi</strong>: 'Likewise you also should be glad and rejoice with me.' The mutual joy: even if Paul is executed, both he and the Philippians should rejoice — because his death would be a sacrificial act completing the gospel work. Joy is not mood-dependent but stems from the theological reality of what suffering means in Christ.</p>",
    "19": "<p><strong>elpizō de en kyriō Iēsou Timotheon tacheōs pempsai hymin hina kagō euthymō gnous ta peri hymōn</strong>: 'I hope in the Lord Jesus to send Timothy to you soon, so that I too may be cheered by news of you.' The hope is qualified <em>en kyriō Iēsou</em> (in the Lord Jesus) — Paul's plans are subject to the Lord's will (cf. Jas 4:15). Timothy as emissary: his sending extends Paul's own pastoral concern.</p>",
    "20": "<p><strong>oudena gar echo isopsychon hostis gnēsiōs ta peri hymōn merimnēsei</strong>: 'For I have no one like him (<em>isopsychon</em> — of equal soul), who will be genuinely concerned for your welfare.' <em>Isopsychos</em> (equal-souled, like-minded) — a Pauline hapax. Timothy's genuine (<em>gnēsiōs</em> — legitimately, not pretended) care for the Philippians mirrors Paul's own. The others seek their own interests (v.21), not the things of Christ Jesus — an implicit contrast with the Christ-hymn's self-emptying pattern.</p>",
    "21": "<p><strong>hoi pantes gar ta heautōn zētousin, ou ta Iesou Christou</strong>: 'For they all seek their own interests, not those of Jesus Christ.' The stark contrast to the Christ-hymn's principle (v.4: look not to your own interests) and to Timothy's character. Those seeking their own interests represent the worldly pattern; Timothy represents the Christomorphic pattern.</p>",
    "22": "<p><strong>tēn de dokimēn autou ginōskete hoti hōs patri teknon syn emoi edouleusen eis to euangelion</strong>: 'But you know Timothy's proven worth (<em>dokimē</em>), how as a son with a father he has served with me in the gospel.' <em>Dokimē</em> (proven character, tested quality — from <em>dokimazō</em>: to test by fire). The father-son relationship describes the apprenticeship dynamic of apostolic formation: Timothy learned gospel ministry by serving alongside Paul.</p>",
    "23": "<p><strong>touton men oun elpizō pempsai hōs an aphidō ta peri eme exautēs</strong>: 'I hope therefore to send him just as soon as I see how it will go with me.' The uncertainty about Paul's legal outcome governs the timing. He cannot leave himself until the situation is resolved; Timothy is his advance ambassador.</p>",
    "24": "<p><strong>pepoitha de en kyriō hoti kai autos tacheōs eleusomai</strong>: 'and I trust in the Lord that shortly I myself will come also.' The personal visit anticipated <em>en kyriō</em> — subject to divine permission. Despite imprisonment, Paul anticipates release and reunion with the congregation he loves.</p>",
    "25": "<p><strong>anagkaion de hēgēsamēn Epaphroditon ton adelphon kai synergon kai systratiōtēn mou hymōn de apostolon kai leitourgon tēs chreias mou pempsai pros hymas</strong>: 'I have thought it necessary to send to you Epaphroditus my brother and fellow worker (<em>synergon</em>) and fellow soldier (<em>systratiōtēn</em>), and your messenger (<em>apostolon</em>) and minister (<em>leitourgon</em>) to my need.' The five-fold description of Epaphroditus: brother, co-worker, co-soldier (evoking military partnership), <em>apostolos</em> (sent one — the Philippians' envoy, using the same term as Paul's apostleship), <em>leitourgos</em> (priestly minister — a cultic term for official service). The priestly vocabulary elevates his service into an act of worship.</p>",
    "26": "<p><strong>epeidē epipothōn ēn pantas hymas kai adēmonōn dioti ēkousate hoti ēsthenēsen</strong>: 'for he has been longing for you all and has been distressed because you heard that he was ill.' <em>Epipothōn</em> (longing for) — the same verb used for Paul's longing for the Philippians (1:8). <em>Adēmonōn</em> (distressed, troubled in spirit) — used in Mark 14:33 for Jesus in Gethsemane. Epaphroditus's pastoral concern for the congregation's anxiety about him is itself a Christomorphic trait.</p>",
    "27": "<p><strong>kai gar ēsthenēsen paraplēsion thanatō alla ho theos ēleēsen auton, ouk auton de monon alla kai eme hina mē lypēn epi lypēn schō</strong>: 'Indeed he was ill, near to death. But God had mercy on him, and not only on him but on me also, lest I should have sorrow upon sorrow.' The honest acknowledgment of Epaphroditus's near-fatal illness — prayer does not always prevent suffering, but God showed mercy. The <em>lypēn epi lypēn</em> (sorrow upon sorrow) Paul would have suffered: his own imprisonment-sorrow plus the grief of losing his co-worker.</p>",
    "28": "<p><strong>spoudaioterōs oun epempsa auton hina idontes auton palin charēte kagō alypoteros ō</strong>: 'I am the more eager to send him, therefore, that you may rejoice at seeing him again, and that I may be less anxious.' The mutual joy of reunion: the congregation's rejoicing at Epaphroditus's return becomes Paul's relief. The pastoral economy of shared joy circulates throughout the letter.</p>",
    "29": "<p><strong>prsdechesthe oun auton en kyriō meta pasēs charas kai tous toioutous entimous echete</strong>: 'So receive him in the Lord with all joy (<em>meta pasēs charas</em>), and honor (<em>entimous</em>) such men.' The community is to honor those who have served to the point of death (v.30). <em>Entimos</em> (honored, precious, valued) — the counter-cultural reversal: Paul calls the congregation to honor the servant-martyr rather than the socially powerful.</p>",
    "30": "<p><strong>hoti dia to ergon Christou mechri thanatou ēngisen paraboleusamenos tē psychē hina anaplērōsē to hymōn hysterēma tēs pros me leitourgias</strong>: 'for he nearly died for the work of Christ, risking his life (<em>paraboleusamenos tē psychē</em>) to complete what was lacking (<em>hysterēma</em>) in your service to me.' <em>Paraboleusamenos</em> (risking, gambling with — from <em>parabolos</em>, one who ventures, takes risks): Epaphroditus gambled his life in service. The <em>hysterēma</em> (lack, deficiency) the Philippians could not supply in person because of distance — Epaphroditus supplied it by his presence and service.</p>",
  },
  "3": {
    "1": "<p><strong>To loipon, adelphoi mou, chairete en kyriō. Ta auta graphein hymin emoi men ouk oknēron hymin de asphales</strong>: 'Finally, my brothers, rejoice in the Lord. To write the same things to you is no trouble to me and is safe for you.' <em>Chairete en kyriō</em> (rejoice in the Lord) — the letter's thematic summons. The 'same things' may refer to repeated warnings about the Judaizers or to the repeated call to joy. <em>Asphales</em> (safe, firm — a nautical term for securely anchored): the repetition is a safety measure for the congregation's doctrinal stability.</p>",
    "2": "<p><strong>blepete tous kynas, blepete tous kakous ergatas, blepete tēn katatomēn</strong>: 'Look out for the dogs (<em>kynas</em>), look out for the evil workers (<em>kakous ergatas</em>), look out for those who mutilate the flesh (<em>katatomēn</em>).' The triple <em>blepete</em> (look out for, beware) signals urgent warning. <em>Kynas</em>: 'dogs' was a Jewish epithet for Gentiles; Paul inverts it against those who demand Gentile circumcision. <em>Katatomē</em> (mutilation) — a bitter wordplay on <em>peritomē</em> (circumcision): those who insist on circumcision as necessary for salvation are reducing it to mere bodily mutilation without covenant significance.</p>",
    "3": "<p><strong>hēmeis gar esmen hē peritomē hoi pneumati theou latreuontes kai kauchōmenoi en Christō Iēsou kai ouk en sarki pepoithotes</strong>: 'For we are the circumcision (<em>hē peritomē</em>), who worship by the Spirit of God and glory in Christ Jesus and put no confidence in the flesh (<em>sarki</em>).' Paul's audacious counter-claim: the true circumcision is the church — those who worship in/by the Spirit, boast in Christ, and place zero confidence in physical or legal credentials. The definition of the covenant people is pneumatological and christological, not ethnic or ritual.</p>",
    "4": "<p><strong>kaiper egō echōn pepoithēsin kai en sarki. Ei tis dokei allos pepoithenai en sarki, egō mallon</strong>: 'though I myself have reason for confidence in the flesh also. If anyone else thinks he has reason for confidence in the flesh, I have more.' The rhetorical synkrisis (comparison): Paul does not dismiss fleshly credentials as if he lacked them, but out-ranks the Judaizing opponents on their own grounds before dismissing those grounds entirely (vv.7-8).</p>",
    "5": "<p><strong>peritomē oktaēmeros ek genous Israēl phylēs Beniamin Hebraios ex Hebraiōn kata nomon Pharisaios</strong>: 'circumcised on the eighth day, of the people of Israel, of the tribe of Benjamin, a Hebrew of Hebrews; as to the law, a Pharisee.' The pedigree: (1) eighth-day circumcision — Torah-observant birth, not adult conversion; (2) Israel — full ethnic membership; (3) Benjamin — the royal tribe; (4) Hebrew of Hebrews — Aramaic-speaking Palestinian Jewish heritage; (5) Pharisee — the most rigorous Torah movement. This is the curriculum vitae of the highest-status Jewish scholar of Paul's generation.</p>",
    "6": "<p><strong>kata zēlon diōkōn tēn ekklēsian, kata dikaiosynēn tēn en nomō genomenos amemptos</strong>: 'as to zeal, a persecutor of the church; as to righteousness under the law, blameless (<em>amemptos</em>).' The zeal (<em>zēlos</em>) for the Torah that drove Paul to persecute the church (Acts 8:3; 9:1-2; Gal 1:13-14) was itself evidence of his pre-conversion Jewish standing. <em>Amemptos</em> (blameless) — not claiming moral perfection but covenantal compliance: he kept the law's requirements as understood within Pharisaism. This is not self-justification but the inventory of what he has renounced.</p>",
    "7": "<p><strong>[alla] hatina ēn moi kerdē tauta hēgēmai dia ton Christon zēmian</strong>: 'But whatever gain (<em>kerdē</em>) I had, I counted as loss (<em>zēmian</em>) for the sake of Christ.' The accounting metaphor: assets on the credit side of the ledger become debits when Christ is brought into the calculation. <em>Zēmia</em> (loss, damage, financial harm) — the commercial language of profit-and-loss. The entire Jewish credential-portfolio is reclassified as debit.</p>",
    "9": "<p><strong>kai heurethō en autō mē echōn emēn dikaiosynēn tēn ek nomou alla tēn dia pisteōs Christou tēn ek theou dikaiosynēn epi tē pistei</strong>: 'and be found in him, not having a righteousness of my own that comes from the law, but that which comes through faith in Christ (<em>dia pisteōs Christou</em>), the righteousness from God (<em>ek theou dikaiosynēn</em>) that depends on faith.' The two righteousnesses contrasted: (1) <em>ē emē dikaiosynē ek nomou</em>: my own righteousness from the law — self-generated covenantal standing through legal performance; (2) <em>ē dia pisteōs Christou ek theou</em>: the righteousness through faith in Christ from God — externally given, christologically mediated. <em>Dia pisteōs Christou</em>: either faith in Christ (objective genitive: we trust Christ) or the faithfulness of Christ (subjective genitive: Christ's own covenant faithfulness). Both convey christological dependence.</p>",
    "10": "<p><strong>tou gnōnai auton kai tēn dynamin tēs anastaseōs autou kai [tēn] koinōnian [tōn] pathēmatōn autou symmorphizomenos tō thanatō autou</strong>: 'that I may know him and the power of his resurrection (<em>dynamin tēs anastaseōs autou</em>), and may share his sufferings (<em>koinōnian tōn pathēmatōn autou</em>), becoming like him in his death (<em>symmorphizomenos tō thanatō autou</em>).' The participatory knowledge of Christ: <em>gnōnai</em> (to know — relational, experiential, not merely propositional). The three dimensions: resurrection power, suffering partnership, and death-conformity. <em>Symmorphizomenos</em> (being conformed to, becoming like in form) — the christomorphic process applied to the apostle's dying.</p>",
    "11": "<p><strong>ei pōs katantēsō eis tēn exanastasin tēn ek nekrōn</strong>: 'that by any means possible I may attain the resurrection from the dead (<em>exanastasin ek nekrōn</em>).' <em>Exanastasis</em> (out-resurrection — a compound form unique in the NT) — the resurrection out from among the dead, distinguishing the resurrection of believers from mere resuscitation. The <em>ei pōs</em> (if by any means) is not uncertainty about final salvation but apostolic sobriety: he does not presume but presses toward the goal.</p>",
    "12": "<p><strong>ouch hoti ēdē elabon ē ēdē teteleiomai diōkō de ei kai katalabō eph' hō kai katelēmphthēn hypo Christou [Iēsou]</strong>: 'Not that I have already obtained this or am already perfect (<em>teteleiomai</em>), but I press on (<em>diōkō</em>) to make it my own, because Christ Jesus has made me his own (<em>katelēmphthēn hypo Christou</em>).' The Damascus road as capture: Christ seized Paul first; now Paul presses after Christ. <em>Diōkō</em> (I pursue, press after) — the same verb Paul used for his persecution of the church (v.6); his zeal is redirected from law-enforcement to Christ-pursuit.</p>",
    "13": "<p><strong>adelphoi egō emauton ou logizomai kateilēphenai hen de, ta men opisō epilanthanomenos tois de emprosthen epekteinomenos</strong>: 'Brothers, I do not consider that I have made it my own. But one thing I do: forgetting what lies behind (<em>opisō epilanthanomenos</em>) and straining forward (<em>epekteinomenos</em>) to what lies ahead.' <em>Epekteinomenos</em> (stretching out toward, straining forward) — the image of the runner leaning into the finish line. Forgetting the past: both past failures (pre-conversion sin) and past achievements (the credential-list of vv.5-6) are released to press forward.</p>",
    "14": "<p><strong>kata skopon diōkō eis to brabeion tēs anō klēseōs tou theou en Christō Iēsou</strong>: 'I press on toward the goal (<em>skopon</em>) for the prize (<em>brabeion</em>) of the upward call (<em>anō klēseōs</em>) of God in Christ Jesus.' <em>Skopos</em> (target, goal — from <em>skopeō</em>: to look toward). <em>Brabeion</em> (prize — the wreath awarded the winner, 1 Cor 9:24-25). The upward call of God: the divine summons draws the apostle forward and upward. The prize is defined christologically and eschatologically.</p>",
    "15": "<p><strong>hosoi oun teleioi touto phronōmen kai ei ti heterōs phroneite kai touto ho theos hymin apokalypsei</strong>: 'Let those of us who are mature (<em>teleioi</em>) think this way, and if in anything you think otherwise, God will reveal that also to you.' The ironic use of <em>teleioi</em> (perfect/mature — the term the perfectionist opponents might claim): Paul applies it to those who know they are not yet perfect (v.12). The promise of further divine revelation for those with different views is pastorally generous.</p>",
    "16": "<p><strong>plēn eis ho ephthasamen tō autō stoichein</strong>: 'Only let us hold true to what we have attained.' <em>Stoichein</em> (to walk in line, to march in order) — the military term for keeping ranks. The community is to maintain unified progress in what they have already received, not to regress or fracture over contested points.</p>",
    "17": "<p><strong>symmimētai mou ginesthe adelphoi kai skopette tous houtōs peripatountas kathōs echete typon hēmas</strong>: 'Brothers, join in imitating me (<em>symmimētai</em>), and keep your eyes on those who walk according to the example you have in us.' <em>Symmimētai</em> (fellow-imitators, co-imitators — a Pauline hapax): not 'imitate me' alone but 'imitate me together, in company with others who do the same.' The <em>typos</em> (type, pattern, example) — apostolic life as a visible pattern for community formation.</p>",
    "18": "<p><strong>polloi gar peripatousin hous pollakis elegon hymin nyn de kai klaiōn legō tous echthrous tou staurou tou Christou</strong>: 'For many, of whom I have often told you and now tell you even with tears, walk as enemies of the cross of Christ (<em>echthrous tou staurou tou Christou</em>).' The pathos of apostolic warning: Paul weeps. <em>Echthrous tou staurou</em> (enemies of the cross): not theological enemies of the cross-doctrine but those whose manner of life (<em>peripatousin</em>) contradicts the cross's cruciform pattern. Their identity is given in v.19.</p>",
    "19": "<p><strong>hōn to telos apōleia, hōn ho theos hē koilia kai hē doxa en tē aischynē autōn, hoi ta epigeia phronountes</strong>: 'Their end is destruction (<em>apōleia</em>), their god is their belly (<em>koilia</em>), and they glory in their shame, with minds set on earthly things (<em>ta epigeia phronountes</em>).' The three marks of the enemies of the cross: (1) god = belly — appetite/desire rules (libertine interpretation) or food laws elevated to salvation-status (rigorist interpretation); (2) glory in shame — inverting the honor-shame calculus; (3) <em>ta epigeia phronountes</em> — the exact antithesis of the heavenly citizenship (v.20) and the cross's upward call (v.14).</p>",
    "21": "<p><strong>hos metaschēmatisei to sōma tēs tapeinōseōs hēmōn symmorphon tō sōmati tēs doxēs autou kata tēn energeian tou dynasthai auton kai hypotaxai autō ta panta</strong>: 'who will transform (<em>metaschēmatisei</em>) our lowly body (<em>sōma tapeinōseōs</em>) to be like his glorious body (<em>symmorphon tō sōmati tēs doxēs autou</em>), by the power that enables him even to subject all things to himself.' <em>Metaschēmatisei</em> (will transform the outward configuration of — cf. <em>schēma</em> in 2:8). The resurrection body of Christ (<em>sōma doxēs</em>) is the template; the transformation is accomplished by the same power that subjects all things (<em>ta panta</em>) — the universal sovereignty of the exalted Christ. The eschatological end of the letter returns to the Christ-hymn's exaltation language.</p>",
  }
}

